"""Classical metrics: exact_match, F1, BLEU-4, ROUGE-L, accuracy.

Conceptual references:
- ./docs/en.md (this lesson)
- lesson 70 (task spec format) for the metric_name field

Stdlib + numpy. Run: python3 code/main.py
"""

from __future__ import annotations

import math
import re
import sys
from collections import Counter

import numpy as np


TOKEN_RE = re.compile(r"\w+", re.UNICODE)


def tokenize(text: str) -> list[str]:
    return TOKEN_RE.findall(text.lower())


def exact_match(prediction: str, targets: list[str]) -> float:
    if not targets:
        return 0.0
    pred = prediction.strip()
    return 1.0 if any(pred == t.strip() for t in targets) else 0.0


def accuracy(prediction: str, targets: list[str]) -> float:
    return exact_match(prediction, targets)


def f1_score(prediction: str, target: str) -> float:
    pred_tokens = tokenize(prediction)
    tgt_tokens = tokenize(target)
    if not pred_tokens and not tgt_tokens:
        return 1.0
    if not pred_tokens or not tgt_tokens:
        return 0.0
    pred_counts = Counter(pred_tokens)
    tgt_counts = Counter(tgt_tokens)
    overlap = sum((pred_counts & tgt_counts).values())
    if overlap == 0:
        return 0.0
    precision = overlap / sum(pred_counts.values())
    recall = overlap / sum(tgt_counts.values())
    return 2.0 * precision * recall / (precision + recall)


def _ngram_counts(tokens: list[str], n: int) -> Counter:
    if n <= 0:
        raise ValueError("n must be positive")
    if len(tokens) < n:
        return Counter()
    return Counter(tuple(tokens[i:i + n]) for i in range(len(tokens) - n + 1))


def _modified_precision(cand_tokens: list[str], ref_tokens: list[str], n: int) -> tuple[int, int]:
    cand_ngrams = _ngram_counts(cand_tokens, n)
    if not cand_ngrams:
        return (0, 0)
    ref_ngrams = _ngram_counts(ref_tokens, n)
    clipped = 0
    for gram, count in cand_ngrams.items():
        clipped += min(count, ref_ngrams.get(gram, 0))
    total = sum(cand_ngrams.values())
    return (clipped, total)


def _brevity_penalty(cand_len: int, ref_len: int) -> float:
    if cand_len == 0:
        return 0.0
    if cand_len >= ref_len:
        return 1.0
    return math.exp(1.0 - ref_len / cand_len)


def bleu4(prediction: str, reference: str, max_n: int = 4) -> float:
    cand = tokenize(prediction)
    ref = tokenize(reference)
    if not cand:
        return 0.0
    log_p_sum = 0.0
    for n in range(1, max_n + 1):
        clipped, total = _modified_precision(cand, ref, n)
        smoothed_num = clipped + 1
        smoothed_den = total + 1
        log_p_sum += math.log(smoothed_num / smoothed_den)
    geo_mean = math.exp(log_p_sum / max_n)
    bp = _brevity_penalty(len(cand), len(ref))
    return float(bp * geo_mean)


def lcs_length(a: list[str], b: list[str]) -> int:
    n, m = len(a), len(b)
    if n == 0 or m == 0:
        return 0
    dp = np.zeros((n + 1, m + 1), dtype=np.int32)
    for i in range(n):
        ai = a[i]
        row_prev = dp[i]
        row_curr = dp[i + 1]
        for j in range(m):
            if ai == b[j]:
                row_curr[j + 1] = row_prev[j] + 1
            else:
                row_curr[j + 1] = max(row_curr[j], row_prev[j + 1])
    return int(dp[n, m])


def rouge_l(prediction: str, reference: str, beta: float = 1.0) -> float:
    cand = tokenize(prediction)
    ref = tokenize(reference)
    if not cand and not ref:
        return 1.0
    if not cand or not ref:
        return 0.0
    lcs = lcs_length(cand, ref)
    if lcs == 0:
        return 0.0
    precision = lcs / len(cand)
    recall = lcs / len(ref)
    if precision == 0.0 and recall == 0.0:
        return 0.0
    beta_sq = beta * beta
    denom = recall + beta_sq * precision
    if denom == 0:
        return 0.0
    return float((1 + beta_sq) * precision * recall / denom)


METRIC_TABLE = {
    "exact_match": "scalar",
    "accuracy": "scalar",
    "f1": "per_target_max",
    "bleu_4": "per_target_max",
    "rouge_l": "per_target_max",
}


def score(metric_name: str, prediction: str, targets: list[str]) -> float:
    if not targets:
        return 0.0
    if metric_name == "exact_match":
        return exact_match(prediction, targets)
    if metric_name == "accuracy":
        return accuracy(prediction, targets)
    if metric_name == "f1":
        return max(f1_score(prediction, t) for t in targets)
    if metric_name == "bleu_4":
        return max(bleu4(prediction, t) for t in targets)
    if metric_name == "rouge_l":
        return max(rouge_l(prediction, t) for t in targets)
    raise ValueError(f"unknown metric_name: {metric_name}")


def corpus_mean(scores: list[float]) -> float:
    if not scores:
        return 0.0
    return float(np.mean(scores))


def corpus_bleu(predictions: list[str], references: list[str], max_n: int = 4) -> float:
    if len(predictions) != len(references):
        raise ValueError("predictions and references must align")
    if not predictions:
        return 0.0
    total_cand_len = 0
    total_ref_len = 0
    clipped_sums = [0] * max_n
    total_sums = [0] * max_n
    for cand_text, ref_text in zip(predictions, references):
        cand = tokenize(cand_text)
        ref = tokenize(ref_text)
        total_cand_len += len(cand)
        total_ref_len += len(ref)
        for n in range(1, max_n + 1):
            clipped, total = _modified_precision(cand, ref, n)
            clipped_sums[n - 1] += clipped
            total_sums[n - 1] += total
    if total_cand_len == 0:
        return 0.0
    log_p_sum = 0.0
    for n in range(1, max_n + 1):
        num = clipped_sums[n - 1] + 1
        den = total_sums[n - 1] + 1
        log_p_sum += math.log(num / den)
    geo = math.exp(log_p_sum / max_n)
    bp = _brevity_penalty(total_cand_len, total_ref_len)
    return float(bp * geo)


def _reference_examples() -> list[dict]:
    return [
        {"metric": "exact_match", "pred": "41", "targets": ["41"], "expected": 1.0},
        {"metric": "exact_match", "pred": "42", "targets": ["41"], "expected": 0.0},
        {"metric": "f1", "pred": "the cat sat", "targets": ["a cat sat on the mat"], "expected_approx": 0.667},
        {"metric": "f1", "pred": "", "targets": ["the cat"], "expected": 0.0},
        {"metric": "bleu_4", "pred": "the cat sat on the mat",
         "targets": ["the cat sat on the mat"], "expected_approx": 1.0},
        {"metric": "bleu_4", "pred": "the the the the",
         "targets": ["the cat sat on the mat"], "expected_lt": 0.5},
        {"metric": "rouge_l", "pred": "the cat sat",
         "targets": ["the cat sat on the mat"], "expected_approx": 0.667},
        {"metric": "accuracy", "pred": "positive", "targets": ["positive"], "expected": 1.0},
    ]


def demo() -> int:
    print("metric demos (using example vectors):")
    failures = 0
    for ex in _reference_examples():
        actual = score(ex["metric"], ex["pred"], ex["targets"])
        if "expected" in ex:
            ok = abs(actual - ex["expected"]) < 1e-9
            print(f"  {ex['metric']:10s} pred={ex['pred']!r:30s} -> {actual:.4f} expected={ex['expected']}")
            if not ok:
                failures += 1
        elif "expected_approx" in ex:
            ok = abs(actual - ex["expected_approx"]) < 0.05
            print(f"  {ex['metric']:10s} pred={ex['pred']!r:30s} -> {actual:.4f} approx={ex['expected_approx']}")
            if not ok:
                failures += 1
        elif "expected_lt" in ex:
            ok = actual < ex["expected_lt"]
            print(f"  {ex['metric']:10s} pred={ex['pred']!r:30s} -> {actual:.4f} < {ex['expected_lt']}")
            if not ok:
                failures += 1
    preds = ["the cat sat on the mat", "the runner won the race"]
    refs = ["the cat sat on the mat", "the runner crossed the finish line first"]
    corpus = corpus_bleu(preds, refs)
    print(f"  corpus_bleu over 2 examples -> {corpus:.4f}")
    return 0 if failures == 0 else 1


if __name__ == "__main__":
    sys.exit(demo())

"""Tests for exact_match, F1, BLEU-4, ROUGE-L, accuracy, and dispatch."""

from __future__ import annotations

import math
import os
import sys
import unittest

HERE = os.path.dirname(os.path.abspath(__file__))
sys.path.insert(0, os.path.dirname(HERE))

from main import (  # noqa: E402
    accuracy,
    bleu4,
    corpus_bleu,
    corpus_mean,
    exact_match,
    f1_score,
    lcs_length,
    rouge_l,
    score,
    tokenize,
    _brevity_penalty,
    _modified_precision,
    _ngram_counts,
)


class TestTokenize(unittest.TestCase):
    def test_basic_tokenize(self) -> None:
        self.assertEqual(tokenize("The Cat, sat!"), ["the", "cat", "sat"])

    def test_empty(self) -> None:
        self.assertEqual(tokenize(""), [])

    def test_numbers_kept(self) -> None:
        self.assertEqual(tokenize("answer is 41"), ["answer", "is", "41"])


class TestExactMatch(unittest.TestCase):
    def test_hit(self) -> None:
        self.assertEqual(exact_match("41", ["41"]), 1.0)

    def test_miss(self) -> None:
        self.assertEqual(exact_match("42", ["41"]), 0.0)

    def test_strips_whitespace(self) -> None:
        self.assertEqual(exact_match("  41  ", ["41"]), 1.0)

    def test_multi_target_any_hit(self) -> None:
        self.assertEqual(exact_match("yes", ["positive", "yes"]), 1.0)

    def test_empty_targets(self) -> None:
        self.assertEqual(exact_match("anything", []), 0.0)

    def test_accuracy_alias(self) -> None:
        self.assertEqual(accuracy("x", ["x"]), 1.0)


class TestF1(unittest.TestCase):
    def test_identical(self) -> None:
        self.assertAlmostEqual(f1_score("the cat", "the cat"), 1.0)

    def test_disjoint(self) -> None:
        self.assertEqual(f1_score("apple", "orange"), 0.0)

    def test_partial(self) -> None:
        s = f1_score("the cat sat", "a cat sat on the mat")
        self.assertGreater(s, 0.4)
        self.assertLess(s, 0.7)

    def test_empty_prediction(self) -> None:
        self.assertEqual(f1_score("", "target"), 0.0)

    def test_empty_target(self) -> None:
        self.assertEqual(f1_score("pred", ""), 0.0)

    def test_both_empty(self) -> None:
        self.assertEqual(f1_score("", ""), 1.0)

    def test_repeated_token_counts_once_per_overlap(self) -> None:
        s1 = f1_score("cat cat cat", "cat")
        s2 = f1_score("cat", "cat cat cat")
        self.assertEqual(s1, s2)


class TestNgram(unittest.TestCase):
    def test_unigram(self) -> None:
        c = _ngram_counts(["a", "b", "a"], 1)
        self.assertEqual(c[("a",)], 2)
        self.assertEqual(c[("b",)], 1)

    def test_4gram_short_text(self) -> None:
        self.assertEqual(_ngram_counts(["a", "b"], 4), {})

    def test_modified_precision_clips(self) -> None:
        cand = ["the", "the", "the", "the"]
        ref = ["the", "cat", "sat"]
        clipped, total = _modified_precision(cand, ref, 1)
        self.assertEqual(clipped, 1)
        self.assertEqual(total, 4)


class TestBLEU(unittest.TestCase):
    def test_perfect_match(self) -> None:
        s = bleu4("the cat sat on the mat", "the cat sat on the mat")
        self.assertAlmostEqual(s, 1.0, places=2)

    def test_no_match(self) -> None:
        s = bleu4("apple banana cherry date", "the cat sat on the mat")
        self.assertLess(s, 0.3)

    def test_repetition_penalised(self) -> None:
        s = bleu4("the the the the", "the cat sat on the mat")
        self.assertLess(s, 0.5)

    def test_brevity_penalty(self) -> None:
        long_ref = "the cat sat on the mat in the sun on a quiet day"
        s_short = bleu4("the cat", long_ref)
        s_full = bleu4(long_ref, long_ref)
        self.assertLess(s_short, s_full)

    def test_brevity_penalty_function(self) -> None:
        self.assertEqual(_brevity_penalty(10, 10), 1.0)
        self.assertEqual(_brevity_penalty(15, 10), 1.0)
        bp = _brevity_penalty(5, 10)
        self.assertAlmostEqual(bp, math.exp(1 - 10 / 5), places=6)
        self.assertEqual(_brevity_penalty(0, 5), 0.0)

    def test_empty_candidate(self) -> None:
        self.assertEqual(bleu4("", "the cat"), 0.0)

    def test_corpus_bleu(self) -> None:
        preds = ["the cat sat", "the dog ran"]
        refs = ["the cat sat", "the dog ran"]
        s = corpus_bleu(preds, refs)
        self.assertGreater(s, 0.5)


class TestRougeL(unittest.TestCase):
    def test_lcs_basic(self) -> None:
        self.assertEqual(lcs_length(["a", "b", "c", "d"], ["a", "c", "d"]), 3)

    def test_lcs_empty(self) -> None:
        self.assertEqual(lcs_length([], ["a"]), 0)
        self.assertEqual(lcs_length(["a"], []), 0)

    def test_perfect(self) -> None:
        self.assertAlmostEqual(rouge_l("the cat sat", "the cat sat"), 1.0)

    def test_disjoint(self) -> None:
        self.assertEqual(rouge_l("apple", "banana"), 0.0)

    def test_partial(self) -> None:
        s = rouge_l("the cat sat", "the cat sat on the mat")
        self.assertGreater(s, 0.6)
        self.assertLess(s, 0.85)

    def test_word_order_matters(self) -> None:
        s_in_order = rouge_l("a b c", "a b c d")
        s_reverse = rouge_l("c b a", "a b c d")
        self.assertGreater(s_in_order, s_reverse)


class TestDispatcher(unittest.TestCase):
    def test_dispatch_exact_match(self) -> None:
        self.assertEqual(score("exact_match", "41", ["41"]), 1.0)

    def test_dispatch_accuracy(self) -> None:
        self.assertEqual(score("accuracy", "yes", ["yes"]), 1.0)

    def test_dispatch_f1(self) -> None:
        s = score("f1", "the cat", ["a cat"])
        self.assertGreater(s, 0.0)

    def test_dispatch_bleu(self) -> None:
        s = score("bleu_4", "the cat sat", ["the cat sat"])
        self.assertGreater(s, 0.5)

    def test_dispatch_rouge_l(self) -> None:
        s = score("rouge_l", "the cat sat", ["the cat sat"])
        self.assertAlmostEqual(s, 1.0)

    def test_unknown_metric_raises(self) -> None:
        with self.assertRaises(ValueError):
            score("perplexity", "x", ["y"])

    def test_multi_target_takes_max(self) -> None:
        s = score("f1", "the cat", ["a horse", "the cat"])
        self.assertGreater(s, 0.5)

    def test_empty_targets_returns_zero(self) -> None:
        self.assertEqual(score("f1", "x", []), 0.0)


class TestCorpus(unittest.TestCase):
    def test_corpus_mean(self) -> None:
        self.assertAlmostEqual(corpus_mean([1.0, 0.0, 0.5]), 0.5)

    def test_corpus_mean_empty(self) -> None:
        self.assertEqual(corpus_mean([]), 0.0)


if __name__ == "__main__":
    unittest.main()
